<?php namespace App\Repositories\Admission;use App\Repositories\BaseRepository;use App\Models\Admission\WaitingList;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class WaitingListRepository extends BaseRepository{    public function __construct(WaitingList $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function findByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function getActiveWaitingList(): Collection    {        return $this->query()->where('status', 'waiting')->orderBy('priority', 'asc')->orderBy('created_at', 'asc')->get();    }    public function getByPriority(int $priority): Collection    {        return $this->findByField('priority', $priority);    }    public function countWaitingByClass(): Collection    {        return $this->query()->selectRaw('class_id, COUNT(*) as total')->where('status', 'waiting')->groupBy('class_id')->get();    }    public function markAsAdmitted(int $id): bool    {        return $this->update($id, ['status' => 'admitted', 'admitted_at' => now()]);    }}